// Expected request body:
// { "files": [ { name, type/mimeType, data/base64/content } , ... ] }
// Where data/base64/content may be:
// - raw base64
// - data URL: "data:application/pdf;base64,...."
const body = $json.body ?? $json;
let files = body.files ?? body.file ?? [];
if (!Array.isArray(files)) files = [files];
files = files.filter(Boolean);
if (!files.length) {
  throw new Error('No files found in webhook body. Expected {"files":[...]}');
}

const out = [];

for (const f of files) {
  const fileName = f.name || f.fileName || f.filename || 'upload.bin';
  const mimeType = f.type || f.mimeType || f.mimetype || 'application/octet-stream';
  let b64 = f.data || f.base64 || f.content || f.fileData || f.file || null;

  // Some Appsmith file objects only include an "id" pointing to their internal store
  // (e.g. "uppy-..."). If you see that, you are NOT actually sending base64.
  if (!b64 && f.id) {
    throw new Error(`File "${fileName}" did not include base64 content. Got id="${f.id}". Ensure your Appsmith action sends base64 (data or base64 field), not only an id.`);
  }
  if (!b64 || typeof b64 !== 'string') {
    throw new Error(`File "${fileName}" missing base64 content (expected string in data/base64/content). Keys: ${Object.keys(f).join(',')}`);
  }

  // Strip data URL prefix if present
  if (b64.startsWith('data:')) {
    const comma = b64.indexOf(',');
    if (comma === -1) throw new Error(`Invalid data URL for "${fileName}"`);
    b64 = b64.slice(comma + 1);
  }

  // Light validation
  if (b64.length < 16) throw new Error(`Base64 payload too short for "${fileName}"`);

  // Build n8n binary item: { binary: { data: { data:<base64>, mimeType, fileName } } }
  out.push({
    json: { fileName, mimeType },
    binary: {
      data: { data: b64, mimeType, fileName }
    }
  });
}

return out;

// Normalize NocoDB upload response into a stable shape for Appsmith.
// NocoDB typically returns an array of attachment objects, or { files: [...] }.
const r = $json.body ?? $json;
let files = r;
if (r && typeof r === 'object' && Array.isArray(r.files)) files = r.files;
if (!Array.isArray(files)) files = [files];

const outFiles = files.filter(x => x && typeof x === 'object' && (x.path || x.signedPath));

return [{ json: { ok: true, files: outFiles } }];

